import React, { useState } from 'react';
import { View, Text, TextInput, TouchableOpacity, StyleSheet, SafeAreaView, ScrollView } from 'react-native';

export default function App() {
  const [screen, setScreen] = useState('input');
  const [inputText, setInputText] = useState('');
  const [generatedPrompt, setGeneratedPrompt] = useState('');

  const handleGenerate = () => {
    setScreen('generating');
    setTimeout(() => {
      const enhanced = `# Enhanced Prompt\n\n${inputText}\n\n## Context\nYou are a helpful AI assistant.\n\n## Task\nRespond thoughtfully to: "${inputText}"\n\n## Output Format\nProvide clear, structured responses.`;
      setGeneratedPrompt(enhanced);
      setScreen('review');
    }, 1500);
  };

  if (screen === 'input') {
    return (
      <SafeAreaView style={styles.container}>
        <View style={styles.content}>
          <Text style={styles.title}>PromptEngine</Text>
          <Text style={styles.subtitle}>What do you want to build?</Text>

          <TextInput
            style={styles.textInput}
            value={inputText}
            onChangeText={setInputText}
            placeholder="Example: I need help analyzing customer feedback..."
            placeholderTextColor="#666"
            multiline
          />

          <TouchableOpacity
            style={[styles.button, !inputText.trim() && styles.buttonDisabled]}
            onPress={handleGenerate}
            disabled={!inputText.trim()}
          >
            <Text style={styles.buttonText}>Generate with AI</Text>
          </TouchableOpacity>
        </View>
      </SafeAreaView>
    );
  }

  if (screen === 'generating') {
    return (
      <SafeAreaView style={styles.container}>
        <View style={[styles.content, styles.center]}>
          <Text style={styles.title}>PromptEngine</Text>
          <Text style={styles.loading}>Structuring your prompt...</Text>
        </View>
      </SafeAreaView>
    );
  }

  return (
    <SafeAreaView style={styles.container}>
      <View style={styles.content}>
        <Text style={styles.title}>PromptEngine</Text>
        <Text style={styles.subtitle}>review</Text>

        <ScrollView style={styles.promptBox}>
          <Text style={styles.promptText}>{generatedPrompt}</Text>
        </ScrollView>

        <View style={styles.buttonRow}>
          <TouchableOpacity 
            style={[styles.button, styles.buttonSecondary]} 
            onPress={() => setScreen('input')}
          >
            <Text style={styles.buttonText}>Back</Text>
          </TouchableOpacity>
          <TouchableOpacity style={styles.button}>
            <Text style={styles.buttonText}>Copy</Text>
          </TouchableOpacity>
        </View>
      </View>
    </SafeAreaView>
  );
}

